package com.example.hybrid;

import android.app.Activity;
import android.content.Intent;
import android.os.Bundle;
import android.os.Handler;
import android.os.Looper;
import android.widget.TextView;

import androidx.annotation.Nullable;
import androidx.appcompat.app.AppCompatActivity;

public class MockPaymentActivity extends AppCompatActivity {

    @Override
    protected void onCreate(@Nullable Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);

        TextView tv = new TextView(this);
        tv.setText("Processing payment...");
        setContentView(tv);

        Intent in = getIntent();
        String callbackId = in != null ? in.getStringExtra("callbackId") : null;

        new Handler(Looper.getMainLooper()).postDelayed(() -> {
            Intent out = new Intent();
            out.putExtra("callbackId", callbackId);
            out.putExtra("payload", "{\"status\":\"success\",\"transactionId\":\"tx_" + System.currentTimeMillis() + "\"}");
            setResult(Activity.RESULT_OK, out);
            finish();
        }, 1200);
    }
}

